import xml.etree.ElementTree as ET
from saml import SAMLResponse, Signature

def validate_saml_response(saml_response):
    # Parse the XML response using python3-saml or lxml
    root = ET.fromstring(saml_response)
    
    # Validate that the signature exists and is valid
    signature = Signature(root, 'ds:Signature')
    if not signature.verify():
        raise ValueError('Invalid signature')
    
    # Extract the assertions from the response
    assertions = root.findall('.//saml:Assertion', namespaces={'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'})
    
